import{_ as i,o as t,c as n,ae as s}from"./chunks/framework.DIepHV_Q.js";const h=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),a={name:"guide/index.md"};function o(r,e,l,u,c,p){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="what-s-this" tabindex="-1">What&#39;s this? <a class="header-anchor" href="#what-s-this" aria-label="Permalink to &quot;What&#39;s this?&quot;">​</a></h2><p><code>vite-plugin-svg-icons-ng</code> is a high-performance SVG icon plugin built for Vite.</p><p>It automatically generates SVG sprites from local files and injects them at runtime, allowing you to use SVG icons as easily as regular icons.</p><p>No manual sprite management, no extra requests, and no complex setup—just a clean and reusable icon system.</p><blockquote><p>This project is inspired by vite-plugin-svg-icons. Thanks.</p></blockquote><h2 id="why-this-plugin" tabindex="-1">Why this plugin? <a class="header-anchor" href="#why-this-plugin" aria-label="Permalink to &quot;Why this plugin?&quot;">​</a></h2><p>Using SVG icons in real-world projects often comes with friction:</p><ul><li>Manually managing icon files, imports, and paths</li><li>Using <code>&lt;img src&gt;</code> or inline SVG is verbose and hard to reuse</li><li>Styling (color, size, responsiveness) is awkward</li><li>Updating icons interrupts development flow</li><li>Inconsistent behavior across dev, build, and SSR</li></ul><p>vite-plugin-svg-icons-ng solves these problems:</p><ul><li>Generates SVG sprites automatically from files</li><li>Use icons via <code>&lt;use&gt;</code> with full styling control</li><li>Built-in HMR for instant updates</li><li>Consistent output across dev, build, and SSR</li><li>No extra requests, better performance</li></ul><p>Turning icons from something you manage into something you just use.</p><hr><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><ul><li><p>🚀 Pre-generation &amp; Injection<br> Automatically generates SVG sprites from files and injects them at runtime for global reuse.</p></li><li><p>⚡ High Performance<br> Combines async build processing with caching, updating icons only when needed for a faster, smoother experience.</p></li><li><p>🔥 HMR Support<br> Icons update fast with a polished refresh flow, keeping your development loop smooth and efficient.</p></li><li><p>🧩 SSR Ready<br> Works seamlessly in SSR environments, ensuring consistent rendering without extra setup.</p></li><li><p>🧱 Cross-environment Consistency<br> Ensures identical SVG sprite output across dev, build, and SSR to avoid environment inconsistencies.</p></li><li><p>📦 Out-of-the-box<br> Sensible defaults and comprehensive docs for quick setup and a unified icon system.</p></li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li>Start with <a href="/vite-plugin-svg-icons-ng/guide/quick-start.html">Quick Start</a></li><li>Check <a href="/vite-plugin-svg-icons-ng/guide/options.html">Options</a> for configuration details</li></ul>',17)])])}const g=i(a,[["render",o]]);export{h as __pageData,g as default};
